v_html := E'<!DOCTYPE html>\n<html lang="de">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<meta http-equiv="X-UA-Compatible" content="IE=edge">\n<title>Willkommen im Pro-Tarif</title>\n</head>\n<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: ''Manrope'', Arial, Helvetica, sans-serif; -webkit-text-size-adjust: none; text-size-adjust: none;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f5f5f5;">\n<tr><td align="center" style="padding: 32px 16px;">\n<table width="600" border="0" cellpadding="0" cellspacing="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">\n\n<!-- HEADER -->\n<tr><td style="padding: 28px 32px 20px; text-align: center; border-bottom: 1px solid #eee;">\n<a href="https://rentab.ly" target="_blank" style="display: inline-block;">\n<img src="https://6f36f82794.imgdist.com/pub/bfra/2bnm3c1v/dzm/8g5/nzj/rentably-logo.svg" alt="rentably" width="180" style="display: block; height: auto; border: 0;" />\n</a>\n</td></tr>\n\n<!-- HERO -->\n<tr><td style="padding: 36px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="text-align: center;">\n<tr><td style="padding: 0 0 20px;">\n<div style="display: inline-block; background-color: #EEF4FF; border: 1px solid #d0e3ff; border-radius: 20px; padding: 6px 16px;">\n<span style="color: #3c8af7; font-size: 12px; font-weight: 700; letter-spacing: 0.3px;">PRO AKTIV</span>\n</div>\n</td></tr>\n</table>\n<h1 style="margin: 0 0 12px; color: #1E1E24; font-size: 22px; font-weight: 700; line-height: 1.35; text-align: center;">Ihr Pro-Tarif ist jetzt aktiv</h1>\n<p style="margin: 0 0 8px; color: #555; font-size: 14px; line-height: 1.65;">Hallo <strong style="color: #1E1E24;">{{userName}}</strong>,</p>\n<p style="margin: 0; color: #555; font-size: 14px; line-height: 1.65;">vielen Dank f&uuml;r Ihr Vertrauen. Ab sofort stehen Ihnen alle Pro-Funktionen von rentably uneingeschr&auml;nkt zur Verf&uuml;gung &ndash; unbegrenzt Immobilien, Mieter und Einheiten inklusive.</p>\n</td></tr>\n\n<!-- SECTION TITLE -->\n<tr><td style="padding: 32px 32px 0; text-align: center;">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 16px; font-weight: 700;">Das erwartet Sie im Pro-Tarif</p>\n<p style="margin: 0; color: #888; font-size: 13px;">Alle Funktionen auf einen Blick.</p>\n</td></tr>\n\n<!-- BLOCK 1: FINANZEN -->\n<tr><td style="padding: 20px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #d0e3ff; text-align: center; line-height: 32px; font-size: 14px; font-weight: 700; color: #3c8af7;">1</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">&Uuml;berblick &amp; Finanzen</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Automatischer Bankabgleich &ndash; Mieteingänge automatisch erkennen und zuordnen</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Cashflow, Finanzanalyse &amp; Anlage V &ndash; Ihre Finanzen auf einen Blick, steuerlich vorbereitet</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Mahnwesen &amp; Indexmiete &ndash; Zahlungserinnerungen und automatische Mietanpassung</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Kennzahlen &amp; Prognosen &ndash; datenbasierte Entscheidungen f&uuml;r Ihr Portfolio</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- BLOCK 2: KOMMUNIKATION -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #d0e3ff; text-align: center; line-height: 32px; font-size: 14px; font-weight: 700; color: #3c8af7;">2</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Kommunikation &amp; Zusammenarbeit</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Ticketsystem &amp; Nachrichten &ndash; direkte Kommunikation mit Mietern und Dienstleistern</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Mieterportal &ndash; Ihre Mieter k&ouml;nnen Anliegen selbst&auml;ndig einreichen und Dokumente einsehen</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Multi-User-Konten &ndash; arbeiten Sie gemeinsam im Team an Ihren Immobilien</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- BLOCK 3: DOKUMENTE -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #d0e3ff; text-align: center; line-height: 32px; font-size: 14px; font-weight: 700; color: #3c8af7;">3</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 10px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Dokumente &amp; Abrechnung</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Betriebskostenabrechnung &ndash; in wenigen Schritten erstellen, pr&uuml;fen und versenden</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Dokument-Assistent &ndash; alle Vorlagen f&uuml;r K&uuml;ndigungen, Abmahnungen, Bescheinigungen und mehr</span></td></tr>\n<tr><td style="padding: 0 0 5px;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">2 GB Dokumentenspeicher &ndash; Vertr&auml;ge, Rechnungen und Fotos sicher archivieren</span></td></tr>\n<tr><td style="padding: 0;"><span style="color: #3c8af7; font-size: 13px; margin-right: 6px;">&#10003;</span><span style="color: #555; font-size: 13px; line-height: 1.5;">Priorit&auml;ts-Support (24h) &ndash; schnelle Antworten, wenn Sie Hilfe brauchen</span></td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- CONTINUOUS DEVELOPMENT -->\n<tr><td style="padding: 24px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #EEF4FF; border-radius: 8px; border-left: 4px solid #3c8af7;">\n<tr><td style="padding: 18px 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700;">Stetig weiterentwickelt</p>\n<p style="margin: 0; color: #555; font-size: 13px; line-height: 1.6;">Wir arbeiten kontinuierlich an neuen Funktionen und Verbesserungen. Als Pro-Nutzer profitieren Sie automatisch von allen zuk&uuml;nftigen Updates &ndash; ohne Aufpreis.</p>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- TAX HINT -->\n<tr><td style="padding: 16px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 16px 20px;">\n<p style="margin: 0; color: #888; font-size: 12px; line-height: 1.55;"><strong style="color: #666;">Steuerlicher Hinweis:</strong> Die Kosten f&uuml;r eine Immobilienverwaltungssoftware k&ouml;nnen in der Regel als Werbungskosten bei Eink&uuml;nften aus Vermietung und Verpachtung steuerlich geltend gemacht werden.</p>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- CTA -->\n<tr><td style="padding: 28px 32px 0; text-align: center;">\n<p style="margin: 0 0 16px; color: #555; font-size: 14px; line-height: 1.6;">Entdecken Sie alles, was jetzt f&uuml;r Sie bereitsteht.</p>\n<a href="https://rentab.ly/dashboard" style="display: inline-block; background-color: #3c8af7; color: #ffffff; text-decoration: none; padding: 13px 40px; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: 0.01em;">Zum Dashboard</a>\n</td></tr>\n\n<!-- SUPPORT -->\n<tr><td style="padding: 32px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 18px 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700;">Fragen?</p>\n<p style="margin: 0 0 10px; color: #666; font-size: 13px; line-height: 1.6;">Als Pro-Nutzer genie&szlig;en Sie Priorit&auml;ts-Support. Wir antworten innerhalb von 24 Stunden.</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #555; font-size: 13px;">E-Mail: <a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none; font-weight: 600;">hallo@rentab.ly</a></td></tr>\n<tr><td style="padding: 0; color: #555; font-size: 13px;">WhatsApp: <a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none; font-weight: 600;">+49 30 2233 4468</a></td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- SPACER -->\n<tr><td style="padding: 8px 0 0;">&nbsp;</td></tr>\n\n<!-- FOOTER -->\n<tr><td style="padding: 20px 32px; border-top: 1px solid #eee; text-align: center;">\n<p style="margin: 0 0 4px; color: #999; font-size: 12px;">&copy; 2026 <a href="https://rentab.ly" style="color: #3c8af7; text-decoration: none;">rentably</a></p>\n<p style="margin: 0 0 8px; color: #bbb; font-size: 11px; line-height: 1.5;">Sie erhalten diese E-Mail, weil Sie als Nutzer bei rentably angemeldet sind.</p>\n<p style="margin: 0 0 6px; color: #bbb; font-size: 11px; line-height: 1.8;"><a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none;">hallo@rentab.ly</a>&nbsp;&nbsp;|&nbsp;&nbsp;<a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none;">WhatsApp</a>&nbsp;&nbsp;|&nbsp;&nbsp;Mo &ndash; Fr, 9:00 &ndash; 18:00 Uhr</p>\n<p style="margin: 0; color: #bbb; font-size: 11px; line-height: 1.5;"><a href="https://rentab.ly/datenschutz" style="color: #3c8af7; text-decoration: none;">Datenschutz</a>&nbsp;|&nbsp;<a href="https://rentab.ly/impressum" style="color: #3c8af7; text-decoration: none;">Impressum</a>&nbsp;|&nbsp;<a href="https://rentab.ly/kontakt" style="color: #3c8af7; text-decoration: none;">Kontakt</a></p>\n</td></tr>\n\n</table>\n</td></tr>\n</table>\n</body>\n</html>';

v_text := E'Ihr Pro-Tarif ist jetzt aktiv\n\nHallo {{userName}},\n\nvielen Dank für Ihr Vertrauen. Ab sofort stehen Ihnen alle Pro-Funktionen von rentably uneingeschränkt zur Verfügung – unbegrenzt Immobilien, Mieter und Einheiten inklusive.\n\n\nDAS ERWARTET SIE IM PRO-TARIF\n===============================\n\n1. Überblick & Finanzen\n   - Automatischer Bankabgleich – Mieteingänge automatisch erkennen und zuordnen\n   - Cashflow, Finanzanalyse & Anlage V – Ihre Finanzen auf einen Blick, steuerlich vorbereitet\n   - Mahnwesen & Indexmiete – Zahlungserinnerungen und automatische Mietanpassung\n   - Kennzahlen & Prognosen – datenbasierte Entscheidungen für Ihr Portfolio\n\n2. Kommunikation & Zusammenarbeit\n   - Ticketsystem & Nachrichten – direkte Kommunikation mit Mietern und Dienstleistern\n   - Mieterportal – Ihre Mieter können Anliegen selbständig einreichen und Dokumente einsehen\n   - Multi-User-Konten – arbeiten Sie gemeinsam im Team an Ihren Immobilien\n\n3. Dokumente & Abrechnung\n   - Betriebskostenabrechnung – in wenigen Schritten erstellen, prüfen und versenden\n   - Dokument-Assistent – alle Vorlagen für Kündigungen, Abmahnungen, Bescheinigungen und mehr\n   - 2 GB Dokumentenspeicher – Verträge, Rechnungen und Fotos sicher archivieren\n   - Prioritäts-Support (24h) – schnelle Antworten, wenn Sie Hilfe brauchen\n\n\nSTETIG WEITERENTWICKELT\n-----------------------\nWir arbeiten kontinuierlich an neuen Funktionen und Verbesserungen. Als Pro-Nutzer profitieren Sie automatisch von allen zukünftigen Updates – ohne Aufpreis.\n\nSteuerlicher Hinweis: Die Kosten für eine Immobilienverwaltungssoftware können in der Regel als Werbungskosten bei Einkünften aus Vermietung und Verpachtung steuerlich geltend gemacht werden.\n\n\nEntdecken Sie alles, was jetzt für Sie bereitsteht:\n>> https://rentab.ly/dashboard\n\n\nFRAGEN?\nAls Pro-Nutzer genießen Sie Prioritäts-Support. Wir antworten innerhalb von 24 Stunden.\nE-Mail: hallo@rentab.ly\nWhatsApp: +49 30 2233 4468\n\n--\nrentably | hallo@rentab.ly | WhatsApp: https://wa.me/493022334468\nMo - Fr, 9:00 - 18:00 Uhr\nDatenschutz: https://rentab.ly/datenschutz | Impressum: https://rentab.ly/impressum | Kontakt: https://rentab.ly/kontakt';

UPDATE email_templates
SET
  body_html = v_html,
  body_text = v_text,
  updated_at = now()
WHERE template_key = 'subscription_started' AND language = 'de';

END $$;
